def valid_date(date):
    # Rule 1: The date string is not empty
    if not date:
        return False

    # Check if the format is mm-dd-yyyy (exactly 10 characters with dashes at positions 2 and 5)
    if len(date) != 10 or date[2] != '-' or date[5] != '-':
        return False

    # Split the date string
    parts = date.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    # Check if all parts are numeric
    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(month_str)
        day = int(day_str)
        year = int(year_str)
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (simplified validation as per problem statement)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper zero-padding (two digits for month and day)
    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    return True
