        month = int(mm)
        day = int(dd)
        year = int(yyyy)
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (as per problem statement)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper formatting (no leading zeros issues)
    # The problem examples show '03-11-2000' as valid, so we allow leading zeros
    # But we need to ensure the string format is exactly mm-dd-yyyy
    # Check that the original string matches the expected format pattern
    if len(mm) != 2 or len(dd) != 2 or len(yyyy) != 4:
        return False

    return True
