```python
def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for duplicates - count occurrences of each number
    from collections import Counter
    counts = Counter(lst)
    if any(count > 2 for count in counts.values()):
        return False

    # Check if list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
```

```python
def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for more than one duplicate of any number
    # Count occurrences of each number
    counts = {}
    for num in lst:
        counts[num] = counts.get(num, 0) + 1
        # If any number appears more than twice, return False immediately
        if counts[num] > 2:
            return False

    # Check if the list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
```

