```python
from typing import List

def rolling_max(numbers: List[int]) -> List[int]:
    if not numbers:
        return []

    result = []
    current_max = numbers[0]

    for num in numbers:
        if num > current_max:
            current_max = num
        result.append(current_max)

    return result
```

```python
def flip_case(string: str) -> str:
    """
    Flip lowercase characters to uppercase and uppercase to lowercase.

    Args:
        string: The input string to process

    Returns:
        A new string with case flipped for each alphabetic character
    """
    result = []
    for char in string:
        if char.islower():
            result.append(char.upper())
        elif char.isupper():
            result.append(char.lower())
        else:
            result.append(char)  # Keep non-alphabetic characters unchanged
    return ''.join(result)
```

